Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class MixedEnvironmentTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public MixedEnvironmentTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skipped automatically on Linux/macOS
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void RegistryKey_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI: runs only on local dev machines
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuShader_CompilesSuccessfully()
    {
        var result = GpuCompiler.Compile("shader.hlsl");
        Assert.IsTrue(result.Success);
    }

    // 3. Flaky external API: retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync(
            "Seattle", _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Temp files: TestCleanup runs even if the test fails
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFile = Path.GetTempFileName();
        Exporter.WriteTo(_tempFile);
        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Summary of attributes used:**

| Scenario | Attribute | MSTest version |
|---|---|---|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retries | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | all versions |

**Key points:**
- `[OSCondition]` and `[CICondition]` **skip** (not fail) the test when conditions aren't met.
- `[Retry]` should only be used for genuinely flaky external dependencies — not to mask race conditions or shared-state bugs.
- `[TestCleanup]` is guaranteed to run after each test, even on failure or exception, making it ideal for temp file cleanup.
- Pair `[Retry]` with `[Timeout]` and `TestContext.CancellationToken` so retries don't hang indefinitely.
